            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"chat1","text":"How do you open the chat panel from any page in the app?","options":[{"id":"a","text":"Navigate to /chat in the sidebar only"},{"id":"b","text":"Click the chat icon in the header bar (it also shows your total unread count)","isCorrect":true},{"id":"c","text":"Press Ctrl+C to toggle chat"},{"id":"d","text":"Open the notification panel and switch to the Messages tab"}],"explanation":"The chat icon in the header toggles the slide-out chat panel from any page and shows your total unread badge. You can also open chat full-page at /chat."},{"id":"chat2","text":"What is the difference between a Direct Message and a Channel?","options":[{"id":"a","text":"A Direct Message is a private 1:1 conversation; a Channel is a shared, multi-person conversation (and may be grouped under a Team)","isCorrect":true},{"id":"b","text":"A Channel can only hold two people; a Direct Message can hold many"},{"id":"c","text":"Direct Messages are real-time but Channels require a page refresh"},{"id":"d","text":"There is no difference — they are two names for the same thing"}],"explanation":"A DM is a private 1:1 conversation in the Direct Messages section. A Channel is a shared conversation in the Channels section that can include many members and may belong to a Team."},{"id":"chat3","text":"You want to create a new shared channel for a project team. What do you do?","options":[{"id":"a","text":"Send a DM to everyone individually"},{"id":"b","text":"Click New Group and fill in the channel name, type, description, and members","isCorrect":true},{"id":"c","text":"Go to Admin > Users and create a group there"},{"id":"d","text":"Post an announcement and ask people to reply"}],"explanation":"New Group opens the create-channel dialog where you set the name, channel type, description, and initial members. The channel then appears in the Channels section."},{"id":"chat4","text":"There is an existing channel you are not a member of. How do you find and join it?","options":[{"id":"a","text":"Click Browse Channels to discover existing channels and join one","isCorrect":true},{"id":"b","text":"You cannot join a channel — an admin must add you"},{"id":"c","text":"Search for it in the global search bar at the top of the app"},{"id":"d","text":"Create a new channel with the same name"}],"explanation":"Browse Channels opens the channel browser (backed by /chat/channels/discover) where you can find channels you are not in and join them."},{"id":"chat5","text":"How do you send a message you have typed in the composer?","options":[{"id":"a","text":"Press Enter — the message sends instantly via SignalR","isCorrect":true},{"id":"b","text":"Press Shift+Enter to send"},{"id":"c","text":"Click outside the input box"},{"id":"d","text":"Wait 5 seconds for it to auto-send"}],"explanation":"Press Enter to send. The message input is single-line, so there is no Shift+Enter newline — Enter always sends. Delivery is instant via the SignalR ChatHub."},{"id":"chat6","text":"You want to reply to one message without cluttering the main conversation. What do you use?","options":[{"id":"a","text":"Reply in thread — it opens the thread panel and keeps the side discussion together","isCorrect":true},{"id":"b","text":"Start a new DM with everyone in the channel"},{"id":"c","text":"Edit the original message to add your reply"},{"id":"d","text":"Quote the message in a new channel"}],"explanation":"Reply in thread opens the thread panel for that message. A message with replies shows a 'N replies' link that reopens the thread, keeping side discussions out of the main flow."},{"id":"chat7","text":"You want to link a specific job into a chat message so people can click straight to it. How?","options":[{"id":"a","text":"Paste the job's URL as plain text"},{"id":"b","text":"Type @ in the message box and pick the job from the mention popover","isCorrect":true},{"id":"c","text":"Attach the job as a file"},{"id":"d","text":"You cannot link records in chat"}],"explanation":"Typing @ opens the mention popover where you can @mention a teammate or link a record — a job, part, PO, sales order, quote, and more. The link renders as a clickable chip that opens the record's detail dialog."},{"id":"chat8","text":"Who can post messages in a read-only Broadcast (announcement) channel?","options":[{"id":"a","text":"Anyone who is a member of the channel"},{"id":"b","text":"Only Admins and Managers","isCorrect":true},{"id":"c","text":"Only the person who created the channel"},{"id":"d","text":"No one — broadcast channels are archives"}],"explanation":"Broadcast channels are read-only: only Admins and Managers can post to them. Everyone else reads the announcements but cannot reply in the channel."},{"id":"chat9","text":"An admin is posting an announcement. Which of these can they control?","options":[{"id":"a","text":"Only the message text — nothing else is configurable"},{"id":"b","text":"The scope (company-wide, department, or specific teams), a severity, whether acknowledgment is required, and an expiry","isCorrect":true},{"id":"c","text":"Only which single user receives it"},{"id":"d","text":"The font and color of the message"}],"explanation":"Announcements can be scoped company-wide, to a department, or to specific teams; carry a severity (Info/Warning/Critical); optionally require acknowledgment; optionally expire; and can be created from reusable templates."},{"id":"chat10","text":"A channel is very active and the notifications are distracting, but you still need to be a member. What do you do?","options":[{"id":"a","text":"Leave the channel"},{"id":"b","text":"Mute the channel from its row to silence notifications while staying a member","isCorrect":true},{"id":"c","text":"Delete all the messages"},{"id":"d","text":"Block the other members"}],"explanation":"Mute silences a channel's notifications without removing you. The muted channel shows a notifications_off icon; you remain a member and can still read it."},{"id":"chat11","text":"How are messages marked as read, and what does the header badge show?","options":[{"id":"a","text":"You must click 'Mark as read' on each message; the badge shows your online status"},{"id":"b","text":"Opening a conversation marks its messages read; the header badge shows your total unread count across all DMs and channels","isCorrect":true},{"id":"c","text":"Messages are read after 10 seconds; the badge shows the number of channels"},{"id":"d","text":"You must scroll to the bottom; the badge shows how many people are online"}],"explanation":"Opening a DM or channel automatically marks its messages read (via the read endpoints). The header chat icon badge shows your total unread count across every conversation and updates in real time."},{"id":"chat12","text":"What does a channel member's role (Member, Admin, or Owner) determine?","options":[{"id":"a","text":"Nothing — roles are decorative labels"},{"id":"b","text":"Member reads and posts; Admin can edit and manage the channel; Owner has full control including deleting it","isCorrect":true},{"id":"c","text":"The color of the member's avatar"},{"id":"d","text":"How many messages the member can send per day"}],"explanation":"Channel roles govern permissions: a Member can read and post, an Admin can edit and manage the channel (name, description, icon, members), and an Owner has full control including deleting the channel."}]}"""
